(self.webpackChunkcheatsheet=self.webpackChunkcheatsheet||[]).push([[7670],{9977:(n,s,a)=>{"use strict";a.r(s),a.d(s,{data:()=>t});const t={key:"v-59a998a4",path:"/python/condition/",title:"เงื่อนไข",lang:"en-US",frontmatter:{},excerpt:"",headers:[{level:2,title:"Introduction to IF statement",slug:"introduction-to-if-statement",children:[{level:3,title:"สมการเป็นจริงก็ต่อเมื่อ",slug:"สมการเป็นจริงก็ต่อเมื่อ",children:[]}]},{level:2,title:"Nested IF Statement",slug:"nested-if-statement",children:[]},{level:2,title:"Introduction to ELSE statement",slug:"introduction-to-else-statement",children:[]},{level:2,title:"Introduction to ELIF statement",slug:"introduction-to-elif-statement",children:[]}],filePathRelative:"python/condition/README.md",git:{updatedTime:162676698e4,contributors:[]}}},1126:(n,s,a)=>{"use strict";a.r(s),a.d(s,{default:()=>e});const t=(0,a(6252).uE)('<h1 id="เงื่อนไข" tabindex="-1"><a class="header-anchor" href="#เงื่อนไข" aria-hidden="true">#</a> เงื่อนไข</h1><p>ใน Lecture นี้ พี่มงจะขออธิบายเกี่ยวกับหลักการตัดสินใจของโปรแกรมกันนะครับ<br> โดยปกติแล้ว คอมพิวเตอร์ไม่รู้หรอกว่า หากน้องมี input เข้ามา และน้องต้องการให้มันทำงานต่างกันตามประเภทหรือข้อมูลที่เข้ามา<br></p><p>ตัวอย่างของการตัดสินใจ เช่น</p><ul><li>ถ้าตัวแปร <code>kumamon</code> นั้นเท่ากับ 1112 ก็ให้ปรี้นท์ &quot;Hello World&quot; ออกทางหน้าจอ<br></li><li>แต่หากว่าไม่เท่ากับ 1112 ก็ให้ปรี้นท์ &quot;Go straight to jail&quot; ออกทางหน้าจอ</li></ul><p>จากความหมายด้านบน พี่มงก็จะเขียนโลจิคดังนี้</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>ถ้า (ตัวแปร kumamon เท่ากับ 1112) -&gt; ให้ปรี้นท์ผลลัพท์ &quot;Hello World&quot; ออกทางหน้าจอ\n\nแต่หากว่าไม่เป็นไปตามนั้น -&gt; ให้ปรี้นท์ผลลัพท์ &quot;Go straight to jail&quot;\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>และถ้าน้องจะเขียนโปรแกรม Python ก็จะได้แบบนี้</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token keyword">if</span> <span class="token punctuation">(</span>kumamon <span class="token operator">==</span> <span class="token number">1112</span><span class="token punctuation">)</span><span class="token punctuation">:</span>\n    <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;Hello World&quot;</span><span class="token punctuation">)</span>\n<span class="token keyword">else</span><span class="token punctuation">:</span>\n    <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;Go straight to jail&quot;</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>อ่านโค้ดออกมั้ยเอ่ย ถ้ายังก็ค่อยๆเรียน lecture นี้ละกันครับ</p><h2 id="introduction-to-if-statement" tabindex="-1"><a class="header-anchor" href="#introduction-to-if-statement" aria-hidden="true">#</a> Introduction to <code>IF</code> statement</h2><p><code>IF</code> ในภาษาไทย หมายถึง &quot;หาก&quot; หรือ &quot;เมื่อ&quot; หรือ &quot;ถ้า&quot;<br> และในภาษาโปรแกรมแล้ว หากมีอะไรเป็นจริง ก็จะทำงานบรรทัดที่เกี่ยวข้องกับมัน ตัวอย่างเช่น</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token keyword">if</span> <span class="token punctuation">(</span>kumamon <span class="token operator">==</span> <span class="token string">&quot;cute&quot;</span><span class="token punctuation">)</span><span class="token punctuation">:</span>\n    <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;yessssssssssssss&quot;</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>ในโปรแกรมด้านบน ก็จะอ่านเป็นภาษาไทยว่า ถ้าตัวแปรคุมะมง มีค่าเท่ากับ &quot;cute&quot; ก็ให้ทำการปรี้นท์คำว่า &quot;yessssssssssssss&quot; ออกบนหน้าจอ<br> และเนื่องจากว่า <code>if (kumamon == &quot;cute&quot;)</code> นั้นเป็นจริง ทำให้รันโค้ดที่เกี่ยวข้องกับมัน นั่นก็คือ <code>print(&quot;yessssssssssssss&quot;)</code> นั่นเองครับ</p><div class="custom-container warning"><p class="custom-container-title">WARNING</p><p>พี่มงใช้ <code>==</code> แต่ไม่เลือกที่จะใช้ <code>=</code> ก็เพราะว่า<br><code>=</code> หมายถึงการให้ค่า จากฝั่งขวาที่เป็นข้อมูล ไปสู่ตัวแปรฝั่งซ้ายครับ แต่ <br><code>==</code> คือการเทียบค่าระหว่าง 2 อย่างครับ</p></div><p>คราวนี้ เราจะมาลองทดสอบกับ input ที่แตกต่างกัน โดยใช้โปรแกรมด้านบนกันครับ</p><p>ในตัวอย่างด้านล่างนี้ พี่มงขอกำหนดค่า kumamon เป็น &quot;Happy Kumamon&quot; ก่อนนะครับ</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>kumamon <span class="token operator">=</span> <span class="token string">&quot;Happy Kumamon&quot;</span>\n\n<span class="token comment"># และพี่มงก็จะทำการก้อปโปรแกรมด้านบนมาทำงาน</span>\n<span class="token keyword">if</span> <span class="token punctuation">(</span>kumamon <span class="token operator">==</span> <span class="token string">&quot;cute&quot;</span><span class="token punctuation">)</span><span class="token punctuation">:</span>\n    <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;yessssssssssssss&quot;</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>น้องก็จะสังเกตได้ว่า โปรแกรมมันไม่ปรี้นท์อะไรออกมาเลย<br> ค่าที่อยู่ในตัวแปร kumamon (ที่มีค่าเป็น &quot;Happy Kumamon&quot;) มันไม่ได้เหมือนกับค่าที่เปรียบเทียบ (&quot;cute&quot;) หนิ เลยทำให้บรรทัดปรี้นท์ไม่ได้ทำงานเนื่องจากสมการเป็นจริง เลยไม่ทำการรัน</p><p>ในตัวอย่างต่อไป พี่มงขอกำหนดค่า kumamon เป็น &quot;cute&quot; ครับ</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>kumamon <span class="token operator">=</span> <span class="token string">&quot;cute&quot;</span>\n\n<span class="token comment"># และพี่มงก็จะทำการก้อปโปรแกรมด้านบนมาทำงาน</span>\n<span class="token keyword">if</span> <span class="token punctuation">(</span>kumamon <span class="token operator">==</span> <span class="token string">&quot;cute&quot;</span><span class="token punctuation">)</span><span class="token punctuation">:</span>\n    <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;yessssssssssssss&quot;</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>โปรแกรมได้ปรี้นท์คำว่า &quot;yessssssssssssss&quot; ออกทางหน้าจอแล้ว ว้าวๆ<br> ก็เพราะสมการนั้นเป็นจริงนั่นเอง โค้ดที่เกี่ยวข้องเลยทำงานครับ</p><p>แต่น้องๆก็จะสงสัยว่า แล้วใช้ <code>if</code> หลายบรรทัดได้หรือเปล่าเอ่ย ก็มาลองกันครับ</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>kumamon <span class="token operator">=</span> <span class="token string">&quot;cute&quot;</span>\n\n<span class="token keyword">if</span> <span class="token punctuation">(</span>kumamon <span class="token operator">==</span> <span class="token string">&quot;cute&quot;</span><span class="token punctuation">)</span><span class="token punctuation">:</span>\n    kumamon <span class="token operator">=</span> <span class="token number">1112</span>\n    <span class="token keyword">print</span><span class="token punctuation">(</span>kumamon<span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>น้องลองคิดตามดูครับ ว่าผลลัพท์จะออกมาเป็นอะไร ลองคิดก่อนอ่านบรรทัดต่อไปนะครับ <br>ถ้าน้องตอบว่า 1112 ก็ถือว่าน้องเข้าใจแล้ว อิอิ</p><h3 id="สมการเป็นจริงก็ต่อเมื่อ" tabindex="-1"><a class="header-anchor" href="#สมการเป็นจริงก็ต่อเมื่อ" aria-hidden="true">#</a> สมการเป็นจริงก็ต่อเมื่อ</h3><table><thead><tr><th>ลำดับที่</th><th>เหตุการณ์ที่ทำให้เป็นจริง</th><th>ตัวอย่าง</th></tr></thead><tbody><tr><td>1</td><td>สมการเป็นจริง</td><td><code>if(2 + 2 = 4)</code></td></tr><tr><td>2</td><td>ตัวแปรกับค่าที่เปรียบเทียบมีค่าเท่ากัน</td><td><code>kumamon = &quot;cute&quot;</code><br><code>if(kumamon == &quot;cute&quot;)</code></td></tr><tr><td>3</td><td>ค่าตัวแปรที่เป็นตัวเลขเป็นจำนวนไม่ใช่ 0</td><td><code>kumamon = 1112</code><br><code>if(kumamon)</code></td></tr><tr><td>4</td><td>ค่า Boolean ในตัวแปรเป็นจริง</td><td><code>kumamon = true</code><br><code>if(kumamon)</code></td></tr><tr><td>5</td><td>ค่า logic เป็นจริง</td><td><code>if(true or false)</code></td></tr></tbody></table><h2 id="nested-if-statement" tabindex="-1"><a class="header-anchor" href="#nested-if-statement" aria-hidden="true">#</a> Nested <code>IF</code> Statement</h2><p>บางครั้ง น้องๆอาจจะต้องมีหลายเงื่อนไขหน่อย เพื่อให้น้องทำงานได้นั่นเอง<br> น้องๆอาจจะเขียนแบบนี้ เพื่อให้มีหลายเงื่อนไขก็ได้ครับ</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token keyword">if</span> <span class="token punctuation">(</span>first_name <span class="token operator">==</span> <span class="token string">&quot;Kumamon&quot;</span><span class="token punctuation">)</span><span class="token punctuation">:</span>\n    <span class="token keyword">if</span> <span class="token punctuation">(</span>age <span class="token operator">==</span> <span class="token number">21</span><span class="token punctuation">)</span><span class="token punctuation">:</span>\n        <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;My name is Kumamon&quot;</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>แต่มันก็ยังดูเยอะไปนะ อิอิ<br> ในช่วงต่อไป เราก็จะมาใช้งาน <strong>Logical Operator</strong> กันดีกว่า</p><h2 id="introduction-to-else-statement" tabindex="-1"><a class="header-anchor" href="#introduction-to-else-statement" aria-hidden="true">#</a> Introduction to <code>ELSE</code> statement</h2><p>น้องๆอาจจะสงสัยว่า ถ้าทำแบบนี้ไม่ได้ ก็ทำแบบนี้แทนได้มั้ย<br> ตัว Statement ELSE ก็มาช่วยน้องแล้วจ้า</p><div class="custom-container warning"><p class="custom-container-title">WARNING</p><p><code>ELSE</code> Statement จะต้องใช้กับ <code>IF</code> ทุกครั้ง<br> และอยู่หลัง <code>IF</code> เท่านั้น</p></div><p>ตัวอย่างการใช้งาน else</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token keyword">if</span> <span class="token punctuation">(</span>kumamon <span class="token operator">==</span> <span class="token string">&quot;Cute&quot;</span><span class="token punctuation">)</span><span class="token punctuation">:</span>\n    <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;Cute Kumamon&quot;</span><span class="token punctuation">)</span>\n<span class="token keyword">else</span><span class="token punctuation">:</span>\n    <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;I don&#39;t understand&quot;</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>น้องจะเห็นว่า การเขียน else นั้นจะ</p><ul><li>เขียนไว้หลัง if statement</li><li>else ก็จะไม่มีสมการเพื่อมาทดสอบ logic อยู่เลย <strong>เพราะว่า else จะทำงานทันที หากว่า if ไม่ทำงาน</strong></li></ul><p>แล้วถ้าน้องเจอโจทย์แบบนี้หล่ะ</p><ul><li>หากว่า kumamon = &quot;Cute&quot; ก็ให้ออก &quot;Cute Kumamon&quot;</li><li>หากว่า kumamon = &quot;Happy&quot; ก็ให้ออก &quot;Happy Kumamon&quot;</li><li>หากว่า kumamon = &quot;Funny&quot; ก็ให้ออก &quot;Funny Kumamon&quot;</li><li>แต่ถ้าไม่เหมือนอะไรเลย ก็ให้ออก &quot;I don&#39;t understand&quot;</li></ul><p>น้องก็สามารถเขียนภาษา Python ได้ดังนี้</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token keyword">if</span> <span class="token punctuation">(</span>kumamon <span class="token operator">==</span> <span class="token string">&quot;Cute&quot;</span><span class="token punctuation">)</span><span class="token punctuation">:</span>\n    <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;Cute Kumamon&quot;</span><span class="token punctuation">)</span>\n<span class="token keyword">else</span><span class="token punctuation">:</span>\n    <span class="token keyword">if</span> <span class="token punctuation">(</span>kumamon <span class="token operator">==</span> <span class="token string">&quot;Happy&quot;</span><span class="token punctuation">)</span><span class="token punctuation">:</span>\n        <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;Happy Kumamon&quot;</span><span class="token punctuation">)</span>\n    <span class="token keyword">else</span><span class="token punctuation">:</span>\n        <span class="token keyword">if</span> <span class="token punctuation">(</span>kumamon <span class="token operator">==</span> <span class="token string">&quot;Funny&quot;</span><span class="token punctuation">)</span><span class="token punctuation">:</span>\n            <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;Funny Kumamon&quot;</span><span class="token punctuation">)</span>\n        <span class="token keyword">else</span><span class="token punctuation">:</span>\n            <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;I don&#39;t understand&quot;</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>แต่! มัน! อ่าน! ไม่! ออก! โหวยยยยยยยยย<br> ไม่เอา ไม่เขียนแบบนี้<br> ภาษา Python ยังมาช่วยน้องได้ ด้วยการใช้ keyword นั่นก็คือ <code>elif</code> นั่นเองครับ</p><h2 id="introduction-to-elif-statement" tabindex="-1"><a class="header-anchor" href="#introduction-to-elif-statement" aria-hidden="true">#</a> Introduction to <code>ELIF</code> statement</h2><p>เนื่องจากว่าคนสร้าง Python เค้าคงนอนดี้นๆกับพื้นเลย ถ้าจะเขียน if แล้ว else แล้ว if แล้ว else เยอะแยะ<br> เค้าก็เลยเอาคำว่า <code>if</code> และ <code>else</code> มารวมร่างกัน เป็น <code>elif</code> นั่นเอง (ไม่ใช่มดเขียวแน่ๆอ่ะครับ พี่บอกไว้ก่อน)</p><p>วิธีการใช้งาน <code>elif</code> ก็แสนจะง่ายดาย เหมือน <code>if</code> เลยจ้า</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token keyword">if</span> <span class="token punctuation">(</span>kumamon <span class="token operator">==</span> <span class="token string">&quot;Cute&quot;</span><span class="token punctuation">)</span><span class="token punctuation">:</span>\n    <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;Hello World&quot;</span><span class="token punctuation">)</span>\n<span class="token keyword">elif</span> <span class="token punctuation">(</span>kumamon <span class="token operator">==</span> <span class="token string">&quot;Hello Kumamon&quot;</span><span class="token punctuation">)</span><span class="token punctuation">:</span>\n    <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;Go straight to jail&quot;</span><span class="token punctuation">)</span>\n<span class="token keyword">else</span><span class="token punctuation">:</span>\n    <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;I don&#39;t understand&quot;</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>น้องๆก็จะสังเกตว่า</p><ul><li><code>elif</code> จะอยู่หลังการทำ <code>if</code> ก่อนทุกครั้ง ไม่ว่าจะเป็นกรณีใดๆทั้งสี้น</li><li>Indentation อยู่บรรทัดเดียวกันกับ if และ else เลย</li></ul>',48),e={render:function(n,s){return t}}}}]);